external_knowledge:
- "beacons of leisure" refers to facilities;
- "capable of hosting a vibrant community of at least 50 enthusiasts" refers to facilities with a capacity of at least 50 users;
- "frequency of their pulse" refers to the count of usage events;
- "average and total rhythm of their heartbeat" refer to the average and total duration of facility usage;
- "overall buzz quotient as gauged by visitor feedback" refers to the number of reviews and average rating of the facilities.

sql:
SELECT type_id, type_name, description, is_indoor, is_outdoor
FROM facility_types
WHERE is_indoor = 1 AND is_outdoor = 1;

SELECT name
FROM facilities
ORDER BY name ASC;

